proof fn phi_1_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.satisfied_by(ex),
        (p.pred)(ex) ==> (q.pred)(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_2_entails_and_infinite_chain(spec: TempPred<int>, p: TempPred<int>, q: TempPred<int>, r: TempPred<int>)
    requires
        spec.entails(p),
        spec.entails(q),
        spec.entails(r),
    ensures
        spec.entails(p.and(q).and(r)),
{
    entails_and_temp::<int>(spec, p, q);
    entails_and_temp::<int>(spec, p.and(q), r);
}

proof fn phi_3_entails_and_self_idempotent(spec: TempPred<int>, p: TempPred<int>)
    requires
        spec.entails(p),
    ensures
        spec.entails(p.and(p)),
{
    entails_and_temp::<int>(spec, p, p);
}

proof fn phi_4_valid_implies_entails_anything(p: TempPred<int>, spec: TempPred<int>)
    requires
        valid(p),
    ensures
        spec.entails(p),
{
    assert forall |ex| #[trigger] spec.satisfied_by(ex) implies p.satisfied_by(ex) by {
        implies_apply::<int>(ex, spec, p);
    };
}

